/** Full Encryptus brand lockup (logomark + wordmark). Uses currentColor so it
 * adapts to light/dark themes — set the color on the parent (e.g. var(--c-heading)). */
export function BrandLogo({ height = 24, style }: { height?: number; style?: CSSProperties }) {
  const width = Math.round((height * 271) / 42);
  return (
    <svg
      width={width}
      height={height}
      viewBox="0 0 271 42"
      fill="none"
      role="img"
      aria-label="Encryptus"
      style={{ display: "block", ...style }}
    >
      <path d={BRAND_LOGO_PATH} fill="currentColor" />
    </svg>
  );
}

/** Soft method badge (sidebar / search): background + foreground from method tokens. */
export function MethodBadge({
  m,
  variant = "soft",
  style,
}: {
  m: Method;
  variant?: "soft" | "solid";
  style?: CSSProperties;
}) {
  const key = m.toLowerCase();
  if (variant === "solid") {
    return (
      <span
        style={{
          fontFamily: MONO,
          fontSize: "12.5px",
          fontWeight: 700,
          letterSpacing: ".04em",
          padding: "6px 12px",
          borderRadius: "7px",
          background: `var(--c-m-${key}-solid)`,
          color: `var(--c-m-${key}-solid-fg)`,
          ...style,
        }}
      >
        {m}
      </span>
    );
  }
  return (
    <span
      style={{
        flex: "none",
        width: "46px",
        textAlign: "center",
        fontFamily: MONO,
        fontSize: "9.5px",
        fontWeight: 600,
        padding: "3px 0",
        borderRadius: "5px",
        background: `var(--c-m-${key}-bg)`,
        color: `var(--c-m-${key}-fg)`,
        ...style,
      }}
    >
      {m}
    </span>
  );
}
